 49→              'worker. To learn more, visit https://bit.ly/CRA-PWA'
 50→          )
 51→        })
 52→      } else {
 53→        // Is not localhost. Just register service worker
 54→        registerValidSW(swUrl, config)
 55→      }
 56→    })
 57→  }
 58→}
