import styled, { css } from 'styled-components'

import { breakpoints } from '../../styles/breakpoints'
import { Body } from '../typography'

export type CategoryProps = {
  id?: string
  title: string
  photoUrl: string
  round?: boolean
}

const Container = styled.figure<{ $round: boolean }>(
  ({ $round, theme: { color, borderRadius } }) => css`
    display: flex;
    cursor: pointer;
    position: relative;
    flex-direction: ${$round ? 'column' : 'row'};
    align-items: ${$round ? 'center' : 'start'};
    border-radius: ${borderRadius.s};
    background: ${$round ? color.cardBackground : 'transparent'};
    height: 100%;
    width: 100%;
    min-width: 50px;
    max-width: ${$round ? '200px' : 'auto'};
    max-height: ${$round ? '200px' : '309px'};
    margin: 0;
    padding: ${$round ? '1.5rem 2rem' : '0'};

    &:hover {
      opacity: 0.9;
    }

    @media ${breakpoints.M} {
      padding: ${$round ? '1.5rem 0' : '0'};
    }
  `
)

const Image = styled.img(
  ({ theme: { borderRadius } }) => css`
    object-fit: cover;
    width: auto;
    border-radius: ${borderRadius.s};
    width: 100%;
    height: 100%;
    min-width: 50px;
    min-height: 50px;
    max-height: 300px;
  `
)

const RoundImage = styled(Image)(
  ({ theme: { borderRadius } }) => css`
    border-radius: ${borderRadius.round};
    width: 4.5rem;
    height: 4.5rem;
    min-width: 4.5rem;
    min-height: 4.5rem;
    max-height: 200px;
    @media ${breakpoints.M} {
      width: 6.5rem;
      height: 6.5rem;
      min-width: 6.5rem;
      min-height: 6.5rem;
    }
  `
)

const FloatingTitle = styled.figcaption(
  ({ theme: { color, borderRadius } }) => css`
    position: absolute;
    top: 1.5rem;
    left: 1.5rem;
    border-radius: ${borderRadius.s};
    background: #202020;
    padding: 8px 16px;
    text-shadow: 2px 1px 2px rgba(0, 0, 0, 0.5);
    span {
      color: ${color.white};
    }
  `
)

const Title = styled.figcaption`
  padding-top: 1rem;
`

const Rounded = ({ title, photoUrl: url }: CategoryProps) => (
  <>
    <RoundImage src={url} alt="restaurant category" />
    <Title>
      <Body type="span">{title}</Body>
    </Title>
  </>
)

const Squared = ({ title, photoUrl: url }: CategoryProps) => (
  <>
    <Image src={url} alt="restaurant category" />
    <FloatingTitle>
      <Body type="span" fontWeight="medium">
        {title}
      </Body>
    </FloatingTitle>
  </>
)

export const Category = ({ photoUrl, title, round = false }: CategoryProps) => {
  return (
    <Container $round={round} data-testid={title}>
      {round ? (
        <Rounded photoUrl={photoUrl} title={title} />
      ) : (
        <Squared photoUrl={photoUrl} title={title} />
      )}
    </Container>
  )
}

import styled, { css } from 'styled-components'

import { breakpoints } from '../../styles/breakpoints'
import { FooterCard } from '../FooterCard/FooterCard'
import { Logo } from '../Logo'
import googlePlayBanner from '../../assets/images/googleplay-banner.png'
import appStoreBanner from '../../assets/images/appstore-banner.png'

const FooterContainer = styled.div(
  ({ theme: { color } }) => css`
    min-height: 450px;
    color: ${color.white};
    background: ${color.footerBackground};
    padding: 2rem 0;

    hr {
      color: ${color.white};
      width: 100%;
    }
  `
)

const FooterTop = styled.div`
  display: grid;
  gap: 40px 24px;
  grid-template-columns: repeat(1, 1fr);
  @media ${breakpoints.S} {
    grid-template-columns: repeat(3, 1fr);
  }
  @media ${breakpoints.L} {
    grid-template-columns: repeat(4, 1fr);
  }
`

export const Footer = () => {
  const navigationLinks = [
    {
      name: 'Home',
      href: '/',
    },
    {
      name: 'Categories',
      href: '/categories',
    },
    {
      name: 'About',
      href: '/about',
    },
    {
      name: 'Login',
      href: '/login',
    },
  ]

  const socialMediaLinks = [
    {
      name: 'Facebook',
      href: 'https://facebook.com',
      external: true,
    },
    {
      name: 'Instagram',
      href: 'https://instagram.com',
      external: true,
    },
    {
      name: 'Twitter',
      href: 'https://twitter.com',
      external: true,
    },
  ]

  return (
    <FooterContainer>
      <div className="container">
        <FooterTop>
          <Logo large logoOnly />
          <FooterCard title="Discover us" links={navigationLinks} />
          <FooterCard title="Our social media" links={socialMediaLinks} />
          <FooterCard title="Check our apps">
            <div className="footer-bottom">
              <img
                alt="app store link"
                style={{ width: '120px', marginBottom: '0.5rem' }}
                src={appStoreBanner}
              />
              <img alt="google play link" style={{ width: '120px' }} src={googlePlayBanner} />
            </div>
          </FooterCard>
        </FooterTop>
      </div>
    </FooterContainer>
  )
}

import { useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import styled, { css } from 'styled-components'

import { PageTemplate } from '../../templates/PageTemplate'
import { useFetchRestaurant } from '../../api/hooks'
import { useAppDispatch, useAppSelector } from '../../app-state'
import { CartItem, clearItemAction, saveItemAction, selectCartItems } from '../../app-state/cart'
import { TopBanner } from '../../components/TopBanner'
import { Heading, Body } from '../../components/typography'
import { Badge } from '../../components/Badge'
import { Review } from '../../components/Review'
import { AnimatedIllustration } from '../../components/AnimatedIllustration'
import { ErrorBlock } from '../../components/ErrorBlock'
import { Spinner } from '../../components/Spinner'

import { FoodItemModal } from './components/FoodItemModal'
import { FoodSection } from './components/FoodSection'

const DetailSection = styled.div(
  ({ theme: { color, spacing } }) => css`
    padding-top: 2rem !important;
    padding-bottom: 2rem !important;
    background: ${color.restaurantDetailBackground};
    .review-text {
      color: ${color.reviewText};
      margin-bottom: ${spacing.m};
    }
  `
)

const MenuSection = styled.div(
  ({ theme: { color } }) => css`
    padding-top: 3rem !important;
    padding-bottom: 5rem !important;
    background: ${color.menuSectionBackground};
  `
)

const StyledBadge = styled(Badge)(
  ({ theme: { spacing } }) => css`
    margin-right: ${spacing.s};
  `
)

export const RestaurantDetailPage = () => {
  const { id = '' } = useParams<'id'>()

  const navigate = useNavigate()
  const { restaurant, status, retryRequest } = useFetchRestaurant(id)

  const [selectedItem, setSelectedItem] = useState<CartItem>()
  const closeModal = () => setSelectedItem(undefined)

  const cartItems = useAppSelector(selectCartItems)
  const dispatch = useAppDispatch()
  const addItemToCart = (item: CartItem) => dispatch(saveItemAction(item))
  const clearItemFromCart = (item: CartItem) => dispatch(clearItemAction(item))

  if (status === '500') {
    return (
      <PageTemplate type="sticky-header">
        <ErrorBlock
          title="Something went wrong!"
          body="Our bad, something went wrong on our side."
          image={<AnimatedIllustration animation="NotFound" />}
          onButtonClick={retryRequest}
          buttonText="Try again"
        />
      </PageTemplate>
    )
  }

  if (status === '404') {
    return (
      <PageTemplate type="sticky-header">
        <ErrorBlock
          title="We can't find this page"
          body="This page doesn’t exist, keep looking."
          image={<AnimatedIllustration animation="Error" />}
          onButtonClick={() => navigate('/')}
          buttonText="Home"
        />
      </PageTemplate>
    )
  }

  if (status === 'loading') {
    return (
      <PageTemplate type="sticky-header">
        <Spinner />
      </PageTemplate>
    )
  }

  if (!restaurant) {
    return null
  }

  const { menu, name, rating, specialty, photoUrl, categories } = restaurant

  return (
    <PageTemplate type="sticky-header">
      <FoodItemModal
        item={selectedItem}
        cartItems={cartItems}
        onClose={closeModal}
        onItemSave={addItemToCart}
        onItemRemove={clearItemFromCart}
      />
      <TopBanner photoUrl={photoUrl} onBackClick={() => navigate(-1)} />
      <DetailSection>
        <div className="container">
          <Heading level={2}>{name}</Heading>
          <Body>Specialties: {specialty}</Body>
          <Review rating={rating} />
          <div>{categories?.map((category) => <StyledBadge key={category} text={category} />)}</div>
        </div>
      </DetailSection>
      <MenuSection>
        <div className="container">
          {menu.food && (
            <FoodSection
              title="To eat"
              items={menu.food}
              cartItems={cartItems}
              onItemClick={setSelectedItem}
            />
          )}
          {menu.dessert && (
            <FoodSection
              title="Dessert"
              items={menu.dessert}
              cartItems={cartItems}
              onItemClick={setSelectedItem}
            />
          )}
          {menu.drinks && (
            <FoodSection
              title="To drink"
              items={menu.drinks}
              cartItems={cartItems}
              onItemClick={setSelectedItem}
            />
          )}
        </div>
      </MenuSection>
    </PageTemplate>
  )
}

import { useParams, useNavigate } from 'react-router-dom'
import styled from 'styled-components'

import { useFetchRestaurantsByCategory } from '../../api/hooks'
import { PageTemplate } from '../../templates/PageTemplate'
import { RestaurantCard, RestaurantCardSkeleton } from '../../components/RestaurantCard'
import { TopBanner } from '../../components/TopBanner'
import { categories } from '../../stub/categories'
import sushi from '../../assets/images/sushi.svg'
import { Restaurant } from '../../types'
import { ErrorBlock } from '../../components/ErrorBlock'
import { Breadcrumb } from '../../components/Breadcrumb'

const StyledContainer = styled.div`
  grid-template-columns: repeat(auto-fill, minmax(356px, 1fr));
  gap: 24px;
  display: grid;
  padding-bottom: 5rem;
`

export const CategoryDetailPage = () => {
  const { id } = useParams<'id'>()
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurantsByCategory(id)

  const category = categories.find((cat) => cat.id === id)

  return (
    <PageTemplate>
      <TopBanner
        title={category?.title || 'Oops!'}
        photoUrl={category?.photoUrl}
        onBackClick={() => navigate(-1)}
      />
      <div className="container">
        <Breadcrumb
          items={[
            { label: 'categories', path: '/categories' },
            { label: category?.title?.toLowerCase() || '' },
          ]}
        />
        {status === 'success' && restaurants.length <= 0 && (
          <ErrorBlock
            body="It seems that there are no restaurants in this category yet. Try to come back later?"
            title="This is not the food you're looking for."
            image={<img alt="no restaurants found" src={sushi} />}
            buttonText="See all restaurants"
            onButtonClick={() => {
              navigate('/categories')
            }}
          />
        )}
        <StyledContainer>
          {status === 'loading'
            ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
            : restaurants.map((restaurant: Restaurant, index: number) => (
                <RestaurantCard
                  key={restaurant.name || index}
                  {...restaurant}
                  onClick={() => navigate(`/restaurants/${restaurant.id}`)}
                />
              ))}
        </StyledContainer>
      </div>
    </PageTemplate>
  )
}

