import * as React from 'react'
import styled from 'styled-components'

import { Header, HeaderComponent } from '../components/Header/Header'
import { Footer } from '../components/Footer/Footer'

const Container = styled.div`
  min-height: calc(100vh - 200px);
`

type PageTemplateProperties = {
  type?: 'default' | 'sticky-header' | 'basic'
}

export const PageTemplate: React.FC<React.PropsWithChildren<PageTemplateProperties>> = ({
  type = 'default',
  children,
}) => {
  switch (type) {
    case 'sticky-header': {
      return (
        <>
          <Header sticky />
          <Container>{children}</Container>
          <Footer />
        </>
      )
    }
    case 'basic': {
      return (
        <>
          <HeaderComponent logoOnly />
          <Container>{children}</Container>
        </>
      )
    }
  }

  return (
    <>
      <Header />
      <Container>{children}</Container>
      <Footer />
    </>
  )
}

import styled from 'styled-components'
import { useNavigate } from 'react-router-dom'
import Carousel, { type ArrowProps, type CarouselProps } from 'react-multi-carousel'

import { useFetchRestaurants } from '../../../../api/hooks'
import { IconButton } from '../../../../components/IconButton'
import { PageSection } from '../../../../components/PageSection'
import { RestaurantCard, RestaurantCardSkeleton } from '../../../../components/RestaurantCard'
import { Restaurant } from '../../../../types'
import { isMobile } from '../../../../helpers'

const PreviousButton = styled(IconButton)`
  position: absolute;
  left: 0;
`

const NextButton = styled(IconButton)`
  position: absolute;
  right: 0;
`

type RestaurantsSectionProps = {
  title: string
}

const CustomArrow = (props: Partial<CarouselProps & ArrowProps> & { isNext?: boolean }) => {
  // filter out unnecessary props coming from react-multi-carousel
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { carouselState, rtl, isNext, ...rest } = props
  return isNext ? (
    <NextButton name="arrow-right" {...rest} />
  ) : (
    <PreviousButton name="arrow-left" {...rest} />
  )
}

export const RestaurantsSection = ({ title }: RestaurantsSectionProps) => {
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurants()

  const isOnMobile = isMobile()
  return (
    <PageSection title={title}>
      <Carousel
        draggable={isOnMobile}
        partialVisible={isOnMobile}
        customLeftArrow={<CustomArrow />}
        customRightArrow={<CustomArrow isNext />}
        responsive={{
          desktop: {
            breakpoint: { max: 5000, min: 1024 },
            items: 3,
            slidesToSlide: 3,
          },
          tablet: {
            breakpoint: { max: 1024, min: 464 },
            items: 2,
            paritialVisibilityGutter: 50,
          },
          mobile: {
            breakpoint: { max: 464, min: 0 },
            items: 1,
            paritialVisibilityGutter: 30,
          },
        }}
        containerClass="carousel-container"
        removeArrowOnDeviceType={['tablet', 'mobile']}
        itemClass="carousel-item"
      >
        {status === 'loading'
          ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
          : restaurants.map((restaurant: Restaurant, index: number) => (
              <RestaurantCard
                key={restaurant.name + index}
                {...restaurant}
                onClick={() => navigate(`/restaurants/${restaurant.id}`)}
              />
            ))}
      </Carousel>
    </PageSection>
  )
}

import { useCallback, useEffect, useState } from 'react'

import type { Restaurant } from '../types'

import { api } from './index'

export const useFetchRestaurants = () => {
  const [status, setStatus] = useState('idle')
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    setStatus('loading')

    api
      .getRestaurants()
      .then((res) => {
        setStatus('success')
        setRestaurants(res)
      })
      .catch((error) => {
        const statusCode = error?.response?.status || 500
        setStatus(statusCode.toString())
      })
  }, [retry])

  return {
    status,
    restaurants,
    retryRequest,
  }
}

export const useFetchRestaurantsByCategory = (categoryId?: string) => {
  const [status, setStatus] = useState('idle')
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    if (categoryId) {
      setStatus('loading')

      api
        .getRestaurantsByCategory(categoryId)
        .then((res) => {
          setStatus('success')
          setRestaurants(res)
        })
        .catch((error) => {
          const statusCode = error?.response?.status || 500
          setStatus(statusCode.toString())
        })
    }
  }, [categoryId, retry])

  return {
    status,
    restaurants,
    retryRequest,
  }
}

export const useFetchRestaurant = (id: string) => {
  const [status, setStatus] = useState('idle')
  const [restaurant, setRestaurant] = useState<Restaurant>()
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    setStatus('loading')

    api
      .getRestaurantById(id)
      .then((res) => {
        setStatus('success')
        setRestaurant(res)
      })
      .catch((error) => {
        const statusCode = error?.response?.status || 500
        setStatus(statusCode.toString())
      })
  }, [id, retry])

  return {
    status,
    restaurant,
    retryRequest,
  }
}

