    name: 'Ciao Bella',
    specialty: 'Takeaway lasagna',
    photoUrl:
      'https://images.pexels.com/photos/6267/menu-restaurant-vintage-table.jpg?auto=compress&cs=tinysrgb&dpr=2&h=750&w=1260',
    categories: ['pizza'],
    isNew: true,
    menu: { food, dessert, drinks },
  },
  {
    id: '6',
    name: 'Soup Eno',
    specialty: 'Spinach soup',
    photoUrl: 'https://duyt4h9nfnj50.cloudfront.net/search_home/FastFood.jpg',
    categories: ['asian'],
    menu: { food, dessert, drinks },
  },
]

export const mswHandlers = [
  http.get(BASE_URL, ({ request }) => {
    const url = new URL(request.url)
    const id = url.searchParams.get('id')
    const category = url.searchParams.get('category')

    if (id) {
      const restaurant = restaurants.find((r) => r.id === id)
      if (!restaurant) {
        return new HttpResponse(null, { status: 404 })
      }
      return HttpResponse.json(restaurant)
    }

    if (category) {
      const filtered = restaurants.filter((r) =>
        r.categories?.includes(category)
      )
      return HttpResponse.json(filtered)
    }

    return HttpResponse.json(restaurants)
  }),
]

