import preview from '#.storybook/preview'
import { expect } from 'storybook/test'
import { Button } from './Button'

const meta = preview.meta({
  component: Button,
  tags: ['ai-generated'],
})

export default meta

export const Default = meta.story({
  args: {
    children: 'Order now',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /order now/i })
    await expect(button).toBeVisible()
    await expect(button).toBeEnabled()
  },
})

export const Clear = meta.story({
  args: {
    children: 'Home',
    clear: true,
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /home/i })
    await expect(button).toBeVisible()
  },
})

export const Disabled = meta.story({
  args: {
    children: 'Submit',
    disabled: true,
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /submit/i })
    await expect(button).toBeDisabled()
  },
})

export const WithIcon = meta.story({
  args: {
    children: 'Cart',
    icon: 'cart',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /cart/i })
    await expect(button).toBeVisible()
  },
})

export const CssCheck = meta.story({
  args: {
    children: 'Submit',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /submit/i })
    // Button uses font-family: 'Hind' - proves global CSS loaded
    await expect(getComputedStyle(button).fontFamily).toContain('Hind')
  },
})

