 50→    }
 51→  `
 52→)
 53→
 54→type DefaultProperties = {
 55→  /**
 56→   * Clear button styles leaving just a text
 57→   */
 58→  clear?: boolean
 59→  round?: boolean
 60→  /**
 61→   * Is the button large?
 62→   */
 63→  large?: boolean
 64→  /**
 65→   * Does the button have an icon?
 66→   */
 67→  icon?: IconName
 68→  /**
 69→   * Size of the icon
 70→   */
 71→  iconSize?: number
 72→  /**
 73→   * Is the button disabled?
 74→   */
 75→  disabled?: boolean
 76→  /**
 77→   * Does the button have an icon?
 78→   */
 79→  children?: string | React.ReactNode
 80→  /**
 81→   * Optional click handler
 82→   */
 83→  onClick?: () => void
 84→}
