 4→export const useLockBodyScroll = (shouldLock = false) => {
 5→  useLayoutEffect(() => {
 6→    document.body.style.overflow = shouldLock ? 'hidden' : 'auto'
 7→    if (isMobile()) {
 8→      document.body.style.height = shouldLock ? '100vh' : 'auto'
 9→    }
10→    // Re-enable scrolling when component unmounts
11→    return () => {
12→      document.body.style.overflow = 'auto'
13→      if (isMobile()) {
14→        document.body.style.height = 'auto'
15→      }
16→    }
17→  }, [shouldLock])
18→}
